mapper.select:
SELECT
FROM operation_activity oa LEFT JOIN city c ON c.id = oa.city_id AND c.region = oa.region LEFT JOIN ( SELECT activity_id, COUNT(1) AS item_count FROM operation_activity_item GROUP BY activity_id ) stats ON stats.activity_id = oa.id WHERE oa.region = #{region}
AND (oa.city_id = 0 OR oa.city_id = #{cityId})
AND oa.status = #{status}
ORDER BY oa.updated_at DESC, oa.id DESC

SELECT COUNT(1)
FROM city
WHERE id = #{cityId}
  AND region = #{region}
  AND status = 1

mapper.update:
UPDATE operation_activity
SET status = #{status},
    updated_by = #{updatedBy},
    updated_at = CURRENT_TIMESTAMP
WHERE id = #{id}
  AND region = #{region}

mapper.delete:
DELETE FROM operation_activity
WHERE id = #{id}
  AND region = #{region}

mapper.select:
SELECT COUNT(1)
FROM operation_activity_item
WHERE activity_id = #{activityId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}

    AND id != #{excludeId}

mapper.update:
UPDATE operation_activity_item
SET target_type = #{targetType},
    target_id = #{targetId},
    title = #{title},
    subtitle = #{subtitle},
    image = #{image},
    sort = #{sort},
    extra_json = #{extraJson}
WHERE id = #{id}
  AND activity_id = #{activityId}

UPDATE operation_activity_item
SET status = #{status}
WHERE id = #{id}
  AND activity_id = #{activityId}
  AND EXISTS (
    SELECT 1
    FROM operation_activity oa
    WHERE oa.id = #{activityId}
      AND oa.region = #{region}
  )

mapper.delete:
DELETE FROM operation_activity_item
WHERE id = #{id}
  AND activity_id = #{activityId}
  AND EXISTS (
    SELECT 1
    FROM operation_activity oa
    WHERE oa.id = #{activityId}
      AND oa.region = #{region}
  )

mapper.select:
SELECT COUNT(1)
FROM shop
WHERE id = #{targetId}
  AND region = #{region}
  AND status = 1
  AND is_deleted = FALSE

SELECT COUNT(1)
FROM rank
WHERE id = #{targetId}
  AND region = #{region}
  AND enabled = TRUE

SELECT COUNT(1)
FROM topic
WHERE id = #{targetId}
  AND region = #{region}
  AND status = 1
  AND merged_to_id IS NULL
